export const maxPullRequestPages = 30;
export const pullRequestPageSize = 100;
export class GitHubPaginationError extends Error {
    constructor(message) {
        super(message);
        this.name = 'GitHubPaginationError';
    }
}
function boundedPositiveInteger(value, maximum, name) {
    if (!Number.isSafeInteger(value) || value < 1)
        throw new RangeError(`${name} must be a positive integer`);
    if (value > maximum)
        throw new RangeError(`${name} must not exceed ${maximum}`);
    return value;
}
export async function fetchPullRequestPages(fetchPage, options = {}) {
    const maxPages = boundedPositiveInteger(options.maxPages ?? maxPullRequestPages, maxPullRequestPages, 'maxPages');
    const pageSize = boundedPositiveInteger(options.pageSize ?? pullRequestPageSize, pullRequestPageSize, 'pageSize');
    const all = [];
    for (let page = 1; page <= maxPages; page += 1) {
        const items = await fetchPage(page, pageSize);
        if (!Array.isArray(items))
            throw new TypeError('GitHub page response must be an array');
        if (items.length === 0)
            break;
        all.push(...items);
        if (items.length < pageSize)
            break;
        if (page === maxPages) {
            throw new GitHubPaginationError(`GitHub pagination reached the ${maxPages}-page safety limit before a terminal page`);
        }
    }
    return all;
}
export function nextPageUrl(linkHeader) {
    for (const part of String(linkHeader ?? '').split(',')) {
        const match = part.trim().match(/^<([^>]+)>\s*;\s*rel="([^"]+)"$/i);
        if (match?.[2]?.split(/\s+/).some((relation) => relation.toLowerCase() === 'next')) {
            return match[1] ?? null;
        }
    }
    return null;
}
export async function fetchGitHubLinkPages(initialUrl, fetchPage, options = {}) {
    const maximum = boundedPositiveInteger(options.maxPages ?? maxPullRequestPages, maxPullRequestPages, 'maxPages');
    const initial = new URL(initialUrl);
    const visited = new Set();
    const all = [];
    let current = initial;
    for (let page = 1; page <= maximum && current; page += 1) {
        const currentUrl = current.href;
        if (visited.has(currentUrl))
            throw new GitHubPaginationError('GitHub pagination link cycle detected');
        visited.add(currentUrl);
        const response = await fetchPage(currentUrl);
        if (!Array.isArray(response?.items))
            throw new TypeError('GitHub page response items must be an array');
        all.push(...response.items);
        const next = nextPageUrl(response.link);
        if (!next)
            break;
        if (page === maximum) {
            throw new GitHubPaginationError(`GitHub pagination exceeded the ${maximum}-page safety limit`);
        }
        const resolved = new URL(next, current);
        if (resolved.origin !== initial.origin) {
            throw new GitHubPaginationError('GitHub pagination next link changed origin');
        }
        current = resolved;
    }
    return all;
}
